1166 void Verifier::verifyLoopMetadata(const MDNode *LoopID) {
1167   // Allow empty loop metadata (!{}) so the verifier does not crash on malformed
1168   // IR; skip further checks.
1169   if (LoopID->getNumOperands() == 0)
1170     return;
1171   Check(LoopID->getNumOperands() >= 1,
1172         "llvm.loop metadata must have at least one operand.", LoopID);
1173   for (const MDOperand &Op : llvm::drop_begin(LoopID->operands())) {
1174     MDNode *Option = dyn_cast<MDNode>(Op);
1175     if (!Option || Option->getNumOperands() < 1)
1176       continue;
1177     MDString *Name = dyn_cast<MDString>(Option->getOperand(0));
1178     if (!Name)
1179       continue;
1180     StringRef AttrName = Name->getString();
1181 
1182     // Verify single-operand attributes.
1183     if (llvm::is_contained(LoopSingleOperandAttributeNames, AttrName)) {
1184       Check(Option->getNumOperands() == 1,
1185             "llvm.loop metadata must have exactly one operand.", Option);
1186       continue;
1187     }
1188 
1189     // Verify boolean attributes.
1190     if (llvm::is_contained(LoopBooleanAttributeNames, AttrName)) {
1191       // Boolean loop attribute: exactly 2 operands (name + i1).
1192       Check(Option->getNumOperands() == 2,
1193             "llvm.loop metadata must have exactly two operands.", Option);
1194       auto *Val =
1195           mdconst::dyn_extract_or_null<ConstantInt>(Option->getOperand(1));
1196       Check(Val && Val->getType()->isIntegerTy(1),
1197             "llvm.loop metadata's second operand must be of type i1.", Option);
1198       continue;
1199     }
1200   }
1201 }
