1203 void Verifier::visitValueAsMetadata(const ValueAsMetadata &MD, Function *F) {
1204   Check(MD.getValue(), "Expected valid value", &MD);
1205   Check(!MD.getValue()->getType()->isMetadataTy(),
1206         "Unexpected metadata round-trip through values", &MD, MD.getValue());
1207 
1208   auto *L = dyn_cast<LocalAsMetadata>(&MD);
1209   if (!L)
1210     return;
1211 
1212   Check(F, "function-local metadata used outside a function", L);
1213 
1214   // If this was an instruction, bb, or argument, verify that it is in the
1215   // function that we expect.
1216   Function *ActualF = nullptr;
1217   if (Instruction *I = dyn_cast<Instruction>(L->getValue())) {
1218     Check(I->getParent(), "function-local metadata not in basic block", L, I);
1219     ActualF = I->getParent()->getParent();
1220   } else if (BasicBlock *BB = dyn_cast<BasicBlock>(L->getValue()))
1221     ActualF = BB->getParent();
1222   else if (Argument *A = dyn_cast<Argument>(L->getValue()))
1223     ActualF = A->getParent();
1224   assert(ActualF && "Unimplemented function local metadata case!");
1225 
1226   Check(ActualF == F, "function-local metadata used in wrong function", L);
1227 }
