1234 void Verifier::visitMetadataAsValue(const MetadataAsValue &MDV, Function *F) {
1235   Metadata *MD = MDV.getMetadata();
1236   if (auto *N = dyn_cast<MDNode>(MD)) {
1237     visitMDNode(*N, AreDebugLocsAllowed::No);
1238     return;
1239   }
1240 
1241   // Only visit each node once.  Metadata can be mutually recursive, so this
1242   // avoids infinite recursion here, as well as being an optimization.
1243   if (!MDNodes.insert(MD).second)
1244     return;
1245 
1246   if (auto *V = dyn_cast<ValueAsMetadata>(MD))
1247     visitValueAsMetadata(*V, F);
1248 
1249   if (auto *AL = dyn_cast<DIArgList>(MD))
1250     visitDIArgList(*AL, F);
1251 }
