1041 MDNode *llvm::findOptionMDForLoopID(MDNode *LoopID, StringRef Name) {
1042   // No loop metadata node, no loop properties.
1043   if (!LoopID)
1044     return nullptr;
1045 
1046   // First operand should refer to the metadata node itself, for legacy reasons.
1047   assert(LoopID->getNumOperands() > 0 && "requires at least one operand");
1048   assert(LoopID->getOperand(0) == LoopID && "invalid loop id");
1049 
1050   // Iterate over the metdata node operands and look for MDString metadata.
1051   for (const MDOperand &MDO : llvm::drop_begin(LoopID->operands())) {
1052     MDNode *MD = dyn_cast<MDNode>(MDO);
1053     if (!MD || MD->getNumOperands() < 1)
1054       continue;
1055     MDString *S = dyn_cast<MDString>(MD->getOperand(0));
1056     if (!S)
1057       continue;
1058     // Return the operand node if MDString holds expected metadata.
1059     if (Name == S->getString())
1060       return MD;
1061   }
1062 
1063   // Loop property not found.
1064   return nullptr;
1065 }
1066 
1067 MDNode *llvm::findOptionMDForLoop(const Loop *TheLoop, StringRef Name) {
1068   return findOptionMDForLoopID(TheLoop->getLoopID(), Name);
1069 }
