1071 /// Find string metadata for loop
1072 ///
1073 /// If it has a value (e.g. {"llvm.distribute", 1} return the value as an
1074 /// operand or null otherwise.  If the string metadata is not found return
1075 /// Optional's not-a-value.
1076 std::optional<const MDOperand *>
1077 llvm::findStringMetadataForLoop(const Loop *TheLoop, StringRef Name) {
1078   MDNode *MD = findOptionMDForLoop(TheLoop, Name);
1079   if (!MD)
1080     return std::nullopt;
1081   switch (MD->getNumOperands()) {
1082   case 1:
1083     return nullptr;
1084   case 2:
1085     return &MD->getOperand(1);
1086   default:
1087     llvm_unreachable("loop metadata has 0 or 1 operand");
1088   }
1089 }
1090 
1091 std::optional<bool> llvm::getOptionalBoolLoopAttribute(const Loop *TheLoop,
1092                                                        StringRef Name) {
1093   MDNode *MD = findOptionMDForLoop(TheLoop, Name);
1094   if (!MD)
1095     return std::nullopt;
1096   switch (MD->getNumOperands()) {
1097   case 1:
1098     // When the value is absent it is interpreted as 'attribute set'.
1099     return true;
1100   case 2:
1101     if (ConstantInt *IntMD =
1102             mdconst::extract_or_null<ConstantInt>(MD->getOperand(1).get()))
1103       return IntMD->getZExtValue();
1104     return true;
1105   }
1106   llvm_unreachable("unexpected number of options");
1107 }
1108 
1109 bool llvm::getBooleanLoopAttribute(const Loop *TheLoop, StringRef Name) {
1110   return getOptionalBoolLoopAttribute(TheLoop, Name).value_or(false);
1111 }
