1113 std::optional<int> llvm::getOptionalIntLoopAttribute(const Loop *TheLoop,
1114                                                      StringRef Name) {
1115   const MDOperand *AttrMD =
1116       findStringMetadataForLoop(TheLoop, Name).value_or(nullptr);
1117   if (!AttrMD)
1118     return std::nullopt;
1119 
1120   ConstantInt *IntMD = mdconst::extract_or_null<ConstantInt>(AttrMD->get());
1121   if (!IntMD)
1122     return std::nullopt;
1123 
1124   return IntMD->getSExtValue();
1125 }
