1132 CallBase *llvm::getLoopConvergenceHeart(const Loop *TheLoop) {
1133   BasicBlock *H = TheLoop->getHeader();
1134   for (Instruction &II : *H) {
1135     if (auto *CB = dyn_cast<CallBase>(&II)) {
1136       if (!CB->isConvergent())
1137         continue;
1138       // This is the heart if it uses a token defined outside the loop. The
1139       // verifier has already checked that only the loop intrinsic can use such
1140       // a token.
1141       if (auto *Token = CB->getConvergenceControlToken()) {
1142         auto *TokenDef = cast<Instruction>(Token);
1143         if (!TheLoop->contains(TokenDef->getParent()))
1144           return CB;
1145       }
1146       return nullptr;
1147     }
1148   }
1149   return nullptr;
1150 }
