1170 MDNode *llvm::makePostTransformationMetadata(LLVMContext &Context,
1171                                              MDNode *OrigLoopID,
1172                                              ArrayRef<StringRef> RemovePrefixes,
1173                                              ArrayRef<MDNode *> AddAttrs) {
1174   // First remove any existing loop metadata related to this transformation.
1175   SmallVector<Metadata *, 4> MDs;
1176 
1177   // Reserve first location for self reference to the LoopID metadata node.
1178   MDs.push_back(nullptr);
1179 
1180   // Remove metadata for the transformation that has been applied or that became
1181   // outdated.
1182   if (OrigLoopID) {
1183     for (const MDOperand &MDO : llvm::drop_begin(OrigLoopID->operands())) {
1184       bool IsVectorMetadata = false;
1185       Metadata *Op = MDO;
1186       if (MDNode *MD = dyn_cast<MDNode>(Op)) {
1187         const MDString *S = dyn_cast<MDString>(MD->getOperand(0));
1188         if (S)
1189           IsVectorMetadata =
1190               llvm::any_of(RemovePrefixes, [S](StringRef Prefix) -> bool {
1191                 return S->getString().starts_with(Prefix);
1192               });
1193       }
1194       if (!IsVectorMetadata)
1195         MDs.push_back(Op);
1196     }
1197   }
1198 
1199   // Add metadata to avoid reapplying a transformation, such as
1200   // llvm.loop.unroll.disable and llvm.loop.isvectorized.
1201   MDs.append(AddAttrs.begin(), AddAttrs.end());
1202 
1203   MDNode *NewLoopID = MDNode::getDistinct(Context, MDs);
1204   // Replace the temporary node with a self-reference.
1205   NewLoopID->replaceOperandWith(0, NewLoopID);
1206   return NewLoopID;
1207 }
