1228 void LoopInfoWrapperPass::verifyAnalysis() const {
1229   // LoopInfoWrapperPass is a FunctionPass, but verifying every loop in the
1230   // function each time verifyAnalysis is called is very expensive. The
1231   // -verify-loop-info option can enable this. In order to perform some
1232   // checking by default, LoopPass has been taught to call verifyLoop manually
1233   // during loop pass sequences.
1234   if (VerifyLoopInfo) {
1235     auto &DT = getAnalysis<DominatorTreeWrapperPass>().getDomTree();
1236     LI.verify(DT);
1237   }
1238 }
